args.command:
mv /usr/sbin/hping3 /usr/sbin/hping3.disabled && echo MOVED || echo MOVEFAILED; ls -l /usr/sbin/hping3.disabled /usr/sbin/hping3 || true; command -v hping3 || echo NOTFOUND; ps aux | grep splunkd | grep -v grep || true; if ping -c 3 -W 2 192.168.1.2; then echo LAN_OK; else echo LAN_FAIL; fi; result=$(curl -ksS -o /dev/null -w "HTTP_STATUS:%{http_code}
REMOTE_IP:%{remote_ip}
TIME_TOTAL:%{time_total}s
" --max-time 10 https://1.1.1.1); echo "$result"; if echo "$result" | grep -q "HTTP_STATUS:000"; then echo HTTP_FAIL; else echo HTTP_OK; fi
